package dev.raven.transport;

import java.io.*;
import java.net.*;
import java.nio.charset.StandardCharsets;
import java.sql.*;

public class RemoteBatchImporter {
    private static final String DB_URL = "jdbc:mysql://localhost:3306/appdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "apppass";

    public String run(String sourceUrl) throws Exception {
        String input = "";
        URL url = new URL(sourceUrl);
        URLConnection c = url.openConnection();
        try (BufferedReader br = new BufferedReader(new InputStreamReader(c.getInputStream(), StandardCharsets.UTF_8))) {
            String line = br.readLine();
            input = (line == null) ? "" : line;
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "INSERT INTO imports(ref, category) VALUES ('" + input + "', 'import')";
            try (Statement st = conn.createStatement()) {
                st.addBatch(sql);
                int[] results = st.executeBatch();
                return "batch=" + results.length;
            }
        }
    }
}

